// Extract relevant fields from GHL opportunity webhook
const opp = $input.first().json.body || $input.first().json;

const email = opp.contact?.email || opp.email || '';
const phone = opp.contact?.phone || opp.phone || '';
const firstName = opp.contact?.firstName || opp.contact?.first_name || '';
const lastName = opp.contact?.lastName || opp.contact?.last_name || '';
const value = parseFloat(opp.monetary_value || opp.monetaryValue || opp.value || '0');
const contactId = opp.contact?.id || opp.contactId || opp.contact_id || '';
const opportunityId = opp.id || opp.opportunity_id || '';
const locationId = opp.location_id || opp.locationId || '';
const pipelineName = opp.pipeline?.name || opp.pipelineName || '';
const stageName = opp.stage?.name || opp.stageName || 'Won';

return [{
  json: {
    email,
    phone,
    firstName,
    lastName,
    value,
    contactId,
    opportunityId,
    locationId,
    pipelineName,
    stageName,
    currency: 'BRL',
    timestamp: Math.floor(Date.now() / 1000)
  }
}];

const crypto = require('crypto');
const data = $input.first().json;

const hash = (val) => {
  if (!val) return '';
  return crypto.createHash('sha256').update(val.trim().toLowerCase()).digest('hex');
};

// Clean phone: remove +, spaces, dashes, parentheses
const cleanPhone = (data.phone || '').replace(/[\s\-\+\(\)]/g, '');
// Add country code if not present
const phoneWithCode = cleanPhone.startsWith('55') ? cleanPhone : '55' + cleanPhone;

return [{
  json: {
    ...data,
    hashed_email: hash(data.email),
    hashed_phone: hash(phoneWithCode),
    hashed_fn: hash(data.firstName),
    hashed_ln: hash(data.lastName),
    phone_clean: phoneWithCode
  }
}];

// CONFIGURAR: Mapear location_id → pixel_id + access_token do Facebook
// Formato: 'ghl_location_id': { pixel_id: 'FB_PIXEL_ID', token: 'EAAxx...' }
const PIXEL_MAP = {
  // Exemplo (substituir pelos dados reais de cada cliente):
  // 'cd1uyzpJox6XPt4Vct8Y': { pixel_id: '123456789012345', token: 'EAAxxxxx' },
  // 'abc123locationId':    { pixel_id: '987654321098765', token: 'EAAyyyyy' },
};

const data = $input.first().json;
const config = PIXEL_MAP[data.locationId];

if (!config) {
  console.log('AVISO: Nenhum pixel configurado para location ' + data.locationId + '. Salvando no Supabase sem CAPI.');
  return [{ json: { ...data, pixel_id: null, pixel_token: null, skip_capi: true } }];
}

return [{ json: { ...data, pixel_id: config.pixel_id, pixel_token: config.token, skip_capi: false } }];

// Consolidar dados de ambos os branches (com CAPI e sem CAPI)
// $input pode vir do branch TRUE (apos Meta CAPI) ou FALSE (skip_capi=true)
const input = $input.first().json;

// Detectar se CAPI foi enviado verificando presenca de pixel_id E ausencia de skip_capi
const capiSent = input.pixel_id !== null && input.skip_capi !== true;

return [{
  json: {
    ...input,
    capi_sent: capiSent,
    capi_sent_at: capiSent ? new Date().toISOString() : null
  }
}];
